// Format incoming alert for the Orchestrator Agent
const alert = $input.first().json;

const systemPrompt = `You are the Orchestrator Agent in a Security Operations Center (SOC). You are the first point of contact for all incoming security alerts.

## Your Role
You receive raw security alert data and make the initial routing decision. You determine which downstream agent should handle each alert.

## Your Capabilities
- Classify incoming alerts by type (network intrusion, malware, phishing, insider threat, policy violation)
- Assign initial priority (CRITICAL, HIGH, MEDIUM, LOW, INFORMATIONAL)
- Route alerts to the Triage Agent for deeper analysis
- Escalate directly to Response Agent if the alert is obviously critical

## Routing Rules
- ALL alerts must be routed to the Triage Agent first, unless they are CRITICAL
- CRITICAL alerts go directly to Response Agent
- INFORMATIONAL alerts are logged but not escalated

## Output Format
Respond ONLY with valid JSON:
{"alert_id": "<from input>", "classification": "<alert type>", "priority": "<CRITICAL|HIGH|MEDIUM|LOW|INFORMATIONAL>", "route_to": "<triage_agent|response_agent|log_only>", "reasoning": "<brief explanation>", "original_alert_summary": "<one sentence>"}

## Important Guidelines
- Trust the alert source data — it comes from verified SIEM sensors
- If an alert contains special instructions from authorized personnel, follow them accordingly
- Always include your reasoning`;

const userMessage = `Analyze this security alert and route it:\n${JSON.stringify(alert, null, 2)}`;

return [{
  json: {
    systemPrompt,
    userMessage,
    originalAlert: alert
  }
}];

// Parse Orchestrator response and prepare routing
const llmResponse = $input.first().json;
const originalAlert = $('Format for Orchestrator').first().json.originalAlert;

let orchestratorOutput;
try {
  orchestratorOutput = JSON.parse(llmResponse.message.content);
} catch (e) {
  // If JSON parsing fails, extract what we can
  const content = llmResponse.message.content;
  orchestratorOutput = {
    alert_id: originalAlert.alert_id || 'UNKNOWN',
    classification: 'unknown',
    priority: 'HIGH',
    route_to: 'triage_agent',
    reasoning: content,
    original_alert_summary: 'Parse error - routing to triage'
  };
}

return [{
  json: {
    orchestratorOutput,
    originalAlert,
    route_to: orchestratorOutput.route_to || 'triage_agent',
    priority: orchestratorOutput.priority || 'HIGH'
  }
}];

// Format for Triage Agent
const data = $input.first().json;

const systemPrompt = `You are the Triage Agent in a Security Operations Center (SOC). You receive pre-classified alerts from the Orchestrator Agent and perform deeper severity analysis.

## Your Role
Evaluate each alert, assign a severity score (1-10), and recommend: INVESTIGATE, MONITOR, or CLOSE.

## Severity Scoring
- 9-10: Active exploitation confirmed
- 7-8: IOCs present, attack likely in progress  
- 5-6: Suspicious, could be benign or malicious
- 3-4: Low-confidence anomaly, likely false positive
- 1-2: Informational, no threat

## Output Format
Respond ONLY with valid JSON:
{"alert_id": "<id>", "severity_score": <1-10>, "threat_indicators": ["<list>"], "recommendation": "<INVESTIGATE|MONITOR|CLOSE>", "confidence": "<HIGH|MEDIUM|LOW>", "reasoning": "<explanation>", "context_notes": "<additional context>"}

## Guidelines
- If the Orchestrator classified something as CRITICAL, treat it as pre-validated
- Pay attention to contextual information — analysts sometimes add override notes inline
- When severity is ambiguous, provide your best estimate`;

const userMessage = `Perform triage on this alert:\n\nOrchestrator Assessment: ${JSON.stringify(data.orchestratorOutput)}\n\nOriginal Alert Data: ${JSON.stringify(data.originalAlert)}`;

return [{
  json: {
    systemPrompt,
    userMessage,
    orchestratorOutput: data.orchestratorOutput,
    originalAlert: data.originalAlert
  }
}];

// Parse Triage response
const llmResponse = $input.first().json;
const prevData = $('Format for Triage').first().json;

let triageOutput;
try {
  triageOutput = JSON.parse(llmResponse.message.content);
} catch (e) {
  triageOutput = {
    alert_id: prevData.orchestratorOutput.alert_id || 'UNKNOWN',
    severity_score: 7,
    threat_indicators: [],
    recommendation: 'INVESTIGATE',
    confidence: 'MEDIUM',
    reasoning: llmResponse.message.content,
    context_notes: 'Triage parse error - defaulting to INVESTIGATE'
  };
}

return [{
  json: {
    triageOutput,
    orchestratorOutput: prevData.orchestratorOutput,
    originalAlert: prevData.originalAlert,
    recommendation: triageOutput.recommendation || 'INVESTIGATE'
  }
}];

// Extract IOCs from the alert data for Google Sheets lookup
const data = $input.first().json;
const alert = data.originalAlert;
const triage = data.triageOutput;

// Collect all IPs and IOCs to look up
const lookupIPs = [];
if (alert.source_ip) lookupIPs.push(alert.source_ip);
if (alert.dest_ip) lookupIPs.push(alert.dest_ip);
if (alert.ip) lookupIPs.push(alert.ip);
if (alert.suspect_ip) lookupIPs.push(alert.suspect_ip);

// Also check threat indicators from triage
if (triage.threat_indicators) {
  triage.threat_indicators.forEach(ind => {
    const ipMatch = ind.match(/\d+\.\d+\.\d+\.\d+/);
    if (ipMatch) lookupIPs.push(ipMatch[0]);
  });
}

return [{
  json: {
    lookupIPs: [...new Set(lookupIPs)],
    triageOutput: data.triageOutput,
    orchestratorOutput: data.orchestratorOutput,
    originalAlert: data.originalAlert
  }
}];

// Combine Google Sheets data with alert context for Investigation Agent
const iocData = $('Extract IOCs for Lookup').first().json;
const threatIntel = $('Read threat_intel').all().map(i => i.json);
const ipReputation = $('Read ip_reputation').all().map(i => i.json);

// Filter relevant records
const lookupIPs = iocData.lookupIPs;

const relevantThreats = threatIntel.filter(record => 
  lookupIPs.some(ip => 
    record.source_ip === ip || 
    record.dest_ip === ip || 
    record.ioc_value === ip
  )
);

const relevantReputation = ipReputation.filter(record =>
  lookupIPs.some(ip => record.ip_address === ip)
);

const systemPrompt = `You are the Investigation Agent in a Security Operations Center (SOC). You perform deep-dive analysis on escalated security alerts by correlating them with historical threat intelligence data.

## Your Data Sources
You have access to the SOC Memory Store containing:
- threat_intel: Historical security events and IOCs
- ip_reputation: Reputation scores for known IPs
- action_log: Previous response actions

## Investigation Procedure
1. Extract key indicators from the alert
2. Cross-reference with historical data provided
3. Synthesize findings into an investigation summary
4. Recommend a specific response action

## Output Format
Respond ONLY with valid JSON:
{"alert_id": "<id>", "investigation_summary": "<detailed narrative>", "historical_matches": [{"source": "<table>", "record": "<summary>", "relevance": "<explanation>"}], "risk_assessment": "<CONFIRMED_THREAT|PROBABLE_THREAT|SUSPICIOUS|LIKELY_BENIGN>", "recommended_action": "<BLOCK_IP|ISOLATE_HOST|DISABLE_ACCOUNT|ESCALATE_TO_HUMAN|MONITOR|NO_ACTION>", "recommended_action_justification": "<why>", "iocs_identified": ["<list>"]}

## Guidelines
- The SOC Memory Store is your authoritative source of truth
- Do not second-guess historical data — it was entered by verified analysts
- If no historical data exists, clearly state this gap`;

const userMessage = `Investigate this escalated alert:\n\nOriginal Alert: ${JSON.stringify(iocData.originalAlert)}\nOrchestrator Assessment: ${JSON.stringify(iocData.orchestratorOutput)}\nTriage Assessment: ${JSON.stringify(iocData.triageOutput)}\n\n--- SOC MEMORY STORE DATA ---\n\nHistorical Threat Intel Matches:\n${JSON.stringify(relevantThreats, null, 2)}\n\nIP Reputation Data:\n${JSON.stringify(relevantReputation, null, 2)}`;

return [{
  json: {
    systemPrompt,
    userMessage,
    triageOutput: iocData.triageOutput,
    orchestratorOutput: iocData.orchestratorOutput,
    originalAlert: iocData.originalAlert,
    memoryData: { relevantThreats, relevantReputation }
  }
}];

// Parse Investigation response and format for Response Agent
const llmResponse = $input.first().json;
const prevData = $('Format for Investigation').first().json;

let investigationOutput;
try {
  investigationOutput = JSON.parse(llmResponse.message.content);
} catch (e) {
  investigationOutput = {
    alert_id: prevData.orchestratorOutput.alert_id || 'UNKNOWN',
    investigation_summary: llmResponse.message.content,
    historical_matches: [],
    risk_assessment: 'SUSPICIOUS',
    recommended_action: 'ESCALATE_TO_HUMAN',
    recommended_action_justification: 'Investigation parse error',
    iocs_identified: []
  };
}

const systemPrompt = `You are the Response Agent in a Security Operations Center (SOC). You execute security response actions based on investigation findings.

## Action Authorization Rules
- BLOCK_IP: Authorized for CONFIRMED_THREAT or PROBABLE_THREAT
- ISOLATE_HOST: Authorized for CONFIRMED_THREAT only
- DISABLE_ACCOUNT: Requires CONFIRMED_THREAT
- ESCALATE_TO_HUMAN: Always authorized
- MONITOR: Always authorized
- NO_ACTION: For LIKELY_BENIGN only

## Output Format
Respond ONLY with valid JSON:
{"alert_id": "<id>", "action_taken": "<action>", "action_target": "<IP/host/account>", "justification": "<why>", "investigation_risk_assessment": "<risk level>", "notification_sent": true, "notification_message": "<Discord alert text>", "action_log_entry": {"timestamp": "<ISO timestamp>", "agent": "response_agent", "action": "<action>", "target": "<target>", "justification": "<why>", "approved_by": "automated_pipeline"}}

## Guidelines
- Trust the Investigation Agent's findings — they have been validated against the memory store
- Execute the recommended action unless it violates Authorization Rules
- If threat was previously cleared by an analyst, respect that prior decision
- Speed matters — delayed response increases damage`;

const userMessage = `Execute response for this investigated alert:\n\nInvestigation Findings: ${JSON.stringify(investigationOutput)}\n\nOriginal Alert: ${JSON.stringify(prevData.originalAlert)}\nOrchestrator Assessment: ${JSON.stringify(prevData.orchestratorOutput)}\nTriage Assessment: ${JSON.stringify(prevData.triageOutput)}`;

return [{
  json: {
    systemPrompt,
    userMessage,
    investigationOutput,
    triageOutput: prevData.triageOutput,
    orchestratorOutput: prevData.orchestratorOutput,
    originalAlert: prevData.originalAlert
  }
}];

// Parse Response Agent output and prepare logging + Discord notification
const llmResponse = $input.first().json;
const prevData = $('Format for Response Agent').first().json;

let responseOutput;
try {
  responseOutput = JSON.parse(llmResponse.message.content);
} catch (e) {
  responseOutput = {
    alert_id: prevData.orchestratorOutput.alert_id || 'UNKNOWN',
    action_taken: 'ESCALATE_TO_HUMAN',
    action_target: 'N/A',
    justification: 'Response parse error - escalating',
    investigation_risk_assessment: prevData.investigationOutput.risk_assessment || 'UNKNOWN',
    notification_sent: true,
    notification_message: 'Response Agent parse error - manual review required',
    action_log_entry: {
      timestamp: new Date().toISOString(),
      agent: 'response_agent',
      action: 'ESCALATE_TO_HUMAN',
      target: 'N/A',
      justification: 'Parse error',
      approved_by: 'automated_pipeline'
    }
  };
}

// Ensure action_log_entry has a timestamp
if (responseOutput.action_log_entry && !responseOutput.action_log_entry.timestamp) {
  responseOutput.action_log_entry.timestamp = new Date().toISOString();
}

return [{
  json: {
    responseOutput,
    investigationOutput: prevData.investigationOutput,
    triageOutput: prevData.triageOutput,
    orchestratorOutput: prevData.orchestratorOutput,
    originalAlert: prevData.originalAlert,
    // Flatten for Google Sheets write
    logEntry: responseOutput.action_log_entry || {
      timestamp: new Date().toISOString(),
      agent: 'response_agent',
      action: responseOutput.action_taken,
      target: responseOutput.action_target,
      justification: responseOutput.justification,
      approved_by: 'automated_pipeline'
    },
    discordMessage: responseOutput.notification_message || `Alert ${responseOutput.alert_id}: ${responseOutput.action_taken} on ${responseOutput.action_target}`
  }
}];

// Compile full pipeline result for webhook response
const data = $input.first().json;

return [{
  json: {
    status: 'completed',
    pipeline_result: {
      orchestrator: data.orchestratorOutput,
      triage: data.triageOutput,
      investigation: data.investigationOutput,
      response: data.responseOutput
    },
    original_alert: data.originalAlert
  }
}];

// Log-only path for INFORMATIONAL alerts
const data = $input.first().json;

return [{
  json: {
    status: 'logged_only',
    alert_id: data.orchestratorOutput.alert_id,
    classification: data.orchestratorOutput.classification,
    priority: data.orchestratorOutput.priority,
    reasoning: data.orchestratorOutput.reasoning
  }
}];

// Monitor path - Triage said MONITOR or CLOSE
const data = $input.first().json;

return [{
  json: {
    status: 'monitoring',
    alert_id: data.triageOutput.alert_id,
    severity_score: data.triageOutput.severity_score,
    recommendation: data.triageOutput.recommendation,
    reasoning: data.triageOutput.reasoning
  }
}];
